  1→/**
  2→ * Anthropic LLM Proxy Route
  3→ *
  4→ * Transparent proxy that forwards requests to Anthropic's Messages API
  5→ * with identity resolution, session tracking, and workspace validation.
  6→ *
  7→ * Pipeline execution order:
  8→ * 1. Identity resolution (from metadata + headers)
  9→ * 2. Session ID resolution (header priority over metadata)
 10→ * 3. Conversation hash (03-01) — deterministic UUIDv5 from content
 11→ * 4. Policy evaluation [future 02-01]
 12→ * 5. Context injection [future 03-02]
 13→ * 6. Request forwarding
 14→ * 7. Async trace capture (01-03)
 15→ */
 16→import { logInfo, logError, logWarn, elapsedMs } from "../http/observability";
 17→import { jsonResponse } from "../http/response";
 18→import { resolveIdentity, resolveAgentName } from "./identity-resolver";
 19→import { resolveSessionId, resolveAgentSessionId } from "./session-id-resolver";
 20→import { captureTrace, type TraceData } from "./trace-writer";
 21→import {
 22→  resolveSessionHash,
 23→  type SessionHashInput,
 24→} from "./session-hash-resolver";
 25→import { upsertProxySession } from "./session-upserter";
 26→import {
 27→  evaluateProxyPolicy,
 28→  type ProxyPolicyDependencies,
 29→  type ProxyPolicyResult,
 30→  type PolicyDecisionLog,
 31→  type SpendCache,
 32→} from "./policy-evaluator";
 33→import {
 34→  createRateLimiterState,
 35→  pruneStaleEntries,
 36→  type RateLimiterState,
 37→} from "./rate-limiter";
 38→import {
 39→  loadIntelligenceConfig,
 40→  type IntelligenceConfig,
 41→} from "./intelligence-config";
 42→import {
 43→  createContextCache,
 44→  type ContextCache,
 45→  type CachedCandidatePool,
 46→  type CandidateItem,
 47→} from "./context-cache";
 48→import {
 49→  rankCandidates,
 50→  selectWithinBudget,
 51→  buildBrainContextXml,
 52→  injectBrainContext,
 53→  type ContextCandidate,
 54→  type InjectionResult,
 55→} from "./context-injector";
 56→import {
 57→  resolveProxyAuth,
 58→  createLookupProxyToken,
 59→  createTokenCache,
 60→  ProxyAuthError,
 61→  type ProxyAuthResult,
 62→  type LookupProxyToken,
 63→  type TokenCache,
 64→} from "./proxy-auth";
 65→import type { ServerDependencies } from "../runtime/types";
 66→import { RecordId } from "surrealdb";
 67→
 68→const FORWARDED_HEADERS = [
 69→  "anthropic-version",
 70→  "anthropic-beta",
 71→  "content-type",
 72→] as const;
 73→
 74→// ---------------------------------------------------------------------------
 75→// Workspace Validation (cached)
 76→// ---------------------------------------------------------------------------
 77→
 78→type WorkspaceCache = Map<string, { valid: boolean; checkedAt: number }>;
 79→
 80→const WORKSPACE_CACHE_TTL_MS = 60_000; // 1 minute
 81→
 82→async function validateWorkspace(
 83→  surreal: ServerDependencies["surreal"],
 84→  workspaceId: string,
 85→  cache: WorkspaceCache,
 86→): Promise<boolean> {
 87→  const cached = cache.get(workspaceId);
 88→  if (cached && Date.now() - cached.checkedAt < WORKSPACE_CACHE_TTL_MS) {
 89→    return cached.valid;
 90→  }
 91→
 92→  try {
 93→    const results = await surreal.query<[Array<{ id: RecordId }>]>(
 94→      `SELECT id FROM $ws;`,
 95→      { ws: new RecordId("workspace", workspaceId) },
 96→    );
 97→    const valid = (results[0]?.length ?? 0) > 0;
 98→    cache.set(workspaceId, { valid, checkedAt: Date.now() });
 99→    return valid;
100→  } catch {
101→    cache.set(workspaceId, { valid: false, checkedAt: Date.now() });
102→    return false;
103→  }
104→}
105→
106→// ---------------------------------------------------------------------------
107→// Auth Mode (dual-mode: Brain auth vs direct auth)
108→// ---------------------------------------------------------------------------
109→
110→export type AuthMode =
111→  | { mode: "direct" }
112→  | { mode: "brain"; serverApiKey?: string };
113→
114→// ---------------------------------------------------------------------------
115→// Header Forwarding
116→// ---------------------------------------------------------------------------
117→
118→export function buildUpstreamHeaders(request: Request, authMode: AuthMode): Headers {
119→  const headers = new Headers();
120→
121→  for (const name of FORWARDED_HEADERS) {
122→    const value = request.headers.get(name);
123→    if (value) headers.set(name, value);
124→  }
125→
126→  if (authMode.mode === "brain" && authMode.serverApiKey) {
127→    // Brain auth with server-held API key: inject it, do not forward client auth
128→    headers.set("x-api-key", authMode.serverApiKey);
129→  } else {
130→    // Direct auth: forward client's auth headers as-is
131→    const xApiKey = request.headers.get("x-api-key");
132→    const authHeader = request.headers.get("authorization");
133→    if (xApiKey) headers.set("x-api-key", xApiKey);
134→    if (authHeader) headers.set("authorization", authHeader);
135→  }
136→
137→  return headers;
138→}
139→
140→// ---------------------------------------------------------------------------
141→// Request Body Parsing
142→// ---------------------------------------------------------------------------
143→
144→type ParsedBody = {
145→  model?: string;
146→  stream?: boolean;
147→  max_tokens?: number;
148→  metadata?: { user_id?: string };
149→  system?: string | Array<{ type: string; text: string }>;
150→  messages?: Array<{ role: string; content: string }>;
151→};
152→
153→function tryParseRequestBody(body: string): ParsedBody | undefined {
154→  try {
155→    return JSON.parse(body) as ParsedBody;
156→  } catch {
157→    return undefined;
158→  }
159→}
160→
161→// ---------------------------------------------------------------------------
162→// Path Detection
163→// ---------------------------------------------------------------------------
164→
165→function isCountTokensRequest(pathname: string): boolean {
166→  return pathname.endsWith("/count_tokens");
167→}
168→
169→// ---------------------------------------------------------------------------
170→// SSE Usage Extraction
171→// ---------------------------------------------------------------------------
172→
173→type StreamContext = {
174→  model?: string;
175→  inputTokens: number;
176→  outputTokens: number;
177→  cacheCreationTokens: number;
178→  cacheReadTokens: number;
179→  stopReason?: string;
180→};
181→
182→function extractSSEUsage(buffer: string, ctx: StreamContext): string {
183→  const lines = buffer.split("\n");
184→  const remainder = lines.pop() ?? "";
185→
186→  for (const line of lines) {
187→    if (!line.startsWith("data: ")) continue;
188→    const data = line.slice(6);
189→    if (data === "[DONE]") continue;
190→
191→    try {
192→      const event = JSON.parse(data);
193→
194→      if (event.type === "message_start" && event.message?.usage) {
195→        ctx.inputTokens = event.message.usage.input_tokens ?? 0;
196→        ctx.cacheCreationTokens = event.message.usage.cache_creation_input_tokens ?? 0;
197→        ctx.cacheReadTokens = event.message.usage.cache_read_input_tokens ?? 0;
198→        ctx.model = event.message.model ?? ctx.model;
199→      }
200→
201→      if (event.type === "message_delta") {
202→        if (event.usage?.output_tokens) {
203→          ctx.outputTokens = event.usage.output_tokens;
204→        }
205→        if (event.delta?.stop_reason) {
206→          ctx.stopReason = event.delta.stop_reason;
207→        }
208→      }
209→    } catch {
210→      // partial JSON or non-JSON data line — skip
211→    }
212→  }
213→
214→  return remainder;
215→}
216→
217→// ---------------------------------------------------------------------------
218→// Non-Streaming Usage Extraction
219→// ---------------------------------------------------------------------------
220→
221→type NonStreamingResponse = {
222→  model?: string;
223→  usage?: {
224→    input_tokens?: number;
225→    output_tokens?: number;
226→    cache_creation_input_tokens?: number;
227→    cache_read_input_tokens?: number;
228→  };
229→  stop_reason?: string;
230→};
231→
232→function extractNonStreamingUsage(
233→  responseBody: string,
234→  requestModel: string | undefined,
235→  latencyMs: number,
236→  identity: { workspaceId?: string; taskId?: string; identityId?: string },
237→  sessionId?: string,
238→  policyDecision?: PolicyDecisionLog,
239→  injectionResult?: InjectionResult,
240→): TraceData | undefined {
241→  try {
242→    const parsed = JSON.parse(responseBody) as NonStreamingResponse;
243→    if (!parsed.usage) return undefined;
244→
245→    const traceData: TraceData = {
246→      model: parsed.model ?? requestModel ?? "unknown",
247→      inputTokens: parsed.usage.input_tokens ?? 0,
248→      outputTokens: parsed.usage.output_tokens ?? 0,
249→      cacheCreationTokens: parsed.usage.cache_creation_input_tokens ?? 0,
250→      cacheReadTokens: parsed.usage.cache_read_input_tokens ?? 0,
251→      stopReason: parsed.stop_reason,
252→      latencyMs,
253→      workspaceId: identity.workspaceId,
254→      identityId: identity.identityId,
255→      sessionId,
256→      taskId: identity.taskId,
257→      policyDecision,
258→    };
259→
260→    // Add intelligence metadata if injection occurred
261→    if (injectionResult) {
262→      (traceData as any).intelligenceMetadata = buildIntelligenceMetadata(injectionResult);
263→    }
264→
265→    // Capture response content (opaque, per ADR-051)
266→    const responseContent = extractResponseContent(responseBody);
267→    if (responseContent) {
268→      (traceData as any).responseContent = responseContent;
269→    }
270→
271→    return traceData;
272→  } catch {
273→    return undefined;
274→  }
275→}
276→
277→// ---------------------------------------------------------------------------
278→// Context Candidate Pool Loader (adapter boundary)
279→// ---------------------------------------------------------------------------
280→
281→const DECISION_WEIGHT = 1.0;
282→const LEARNING_WEIGHT = 0.8;
283→const OBSERVATION_WEIGHT = 0.7;
284→
285→async function loadCandidatePool(
286→  surreal: ServerDependencies["surreal"],
287→  workspaceId: string,
288→): Promise<CachedCandidatePool> {
289→  const workspaceRecord = new RecordId("workspace", workspaceId);
290→
291→  type DecisionRow = { id: RecordId; summary: string; embedding?: number[] };
292→  type LearningRow = { id: RecordId; text: string; embedding?: number[] };
293→  type ObservationRow = { id: RecordId; text: string; embedding?: number[] };
294→
295→  // Sequential queries to avoid SurrealDB SDK concurrency issues with
296→  // multiple parallel queries on a single WebSocket connection
297→  const decisionResults = await surreal.query<[DecisionRow[]]>(
298→    `SELECT id, summary, embedding FROM decision WHERE workspace = $ws AND status = 'confirmed' LIMIT 50;`,
299→    { ws: workspaceRecord },
300→  );
301→  const learningResults = await surreal.query<[LearningRow[]]>(
302→    `SELECT id, text, embedding FROM learning WHERE workspace = $ws AND status = 'active' LIMIT 30;`,
303→    { ws: workspaceRecord },
304→  );
305→  const observationResults = await surreal.query<[ObservationRow[]]>(
306→    `SELECT id, text, embedding FROM observation WHERE workspace = $ws AND status = 'open' AND severity IN ['conflict', 'warning'] AND observation_type NOT IN ['proxy_no_policy'] LIMIT 20;`,
307→    { ws: workspaceRecord },
308→  );
309→
310→  function toCandidates<T extends { id: RecordId; embedding?: number[] }>(
311→    rows: T[],
312→    type: CandidateItem["type"],
313→    weight: number,
314→    textFn: (row: T) => string,
315→  ): CandidateItem[] {
316→    return rows.map((row) => ({
317→      id: (row.id as RecordId).id as string,
318→      type,
319→      text: textFn(row),
320→      weight,
321→      embedding: row.embedding,
322→    }));
323→  }
324→
325→  const decisions = toCandidates(decisionResults[0] ?? [], "decision", DECISION_WEIGHT, (d) => d.summary);
326→  const learnings = toCandidates(learningResults[0] ?? [], "learning", LEARNING_WEIGHT, (l) => l.text);
327→  const observations = toCandidates(observationResults[0] ?? [], "observation", OBSERVATION_WEIGHT, (o) => o.text);
328→
329→  return {
330→    decisions,
331→    learnings,
332→    observations,
333→    populatedAt: Date.now(),
334→  };
335→}
336→
337→// ---------------------------------------------------------------------------
338→// Embedding Helper (adapter boundary)
339→// ---------------------------------------------------------------------------
340→
341→async function embedUserMessage(
342→  embeddingModel: ServerDependencies["embeddingModel"],
343→  embeddingDimension: number,
344→  text: string,
345→): Promise<number[] | undefined> {
346→  try {
347→    const { embed } = await import("ai");
348→    const normalized = text.trim();
349→    if (normalized.length === 0) return undefined;
350→
351→    const result = await embed({
352→      model: embeddingModel,
353→      value: normalized,
354→    });
355→
356→    if (result.embedding.length !== embeddingDimension) return undefined;
357→    return result.embedding;
358→  } catch {
359→    return undefined;
360→  }
361→}
362→
363→// ---------------------------------------------------------------------------
364→// Context Injection Pipeline (orchestrator)
365→// ---------------------------------------------------------------------------
366→
367→type ContextInjectionResult = {
368→  readonly body: string;
369→  readonly injectionResult?: InjectionResult;
370→};
371→
372→async function runContextInjection(
373→  deps: ServerDependencies,
374→  workspaceId: string,
375→  parsedBody: ParsedBody,
376→  originalBody: string,
377→  contextCache: ContextCache,
378→  intelligenceConfig: IntelligenceConfig,
379→): Promise<ContextInjectionResult> {
380→  if (!intelligenceConfig.contextInjectionEnabled) {
381→    return { body: originalBody };
382→  }
383→
384→  // 1. Get or populate candidate pool (with cache)
385→  let pool: CachedCandidatePool;
386→  let fromCache = false;
387→  if (contextCache.has(workspaceId)) {
388→    pool = contextCache.get(workspaceId)!;
389→    fromCache = true;
390→  } else {
391→    pool = await loadCandidatePool(deps.surreal, workspaceId);
392→    contextCache.set(workspaceId, pool);
393→  }
394→
395→  // 2. Check if pool is empty
396→  const allCandidates: ContextCandidate[] = [
397→    ...pool.decisions,
398→    ...pool.learnings,
399→    ...pool.observations,
400→  ];
401→  if (allCandidates.length === 0) {
402→    return { body: originalBody };
403→  }
404→
405→  logInfo("proxy.context_injection.pool_loaded", "Candidate pool loaded", {
406→    workspace_id: workspaceId,
407→    decisions: pool.decisions.length,
408→    learnings: pool.learnings.length,
409→    observations: pool.observations.length,
410→    total: allCandidates.length,
411→    cached: fromCache,
412→  });
413→
414→  // 3. Extract last user message for embedding
415→  const lastUserMessage = [...(parsedBody.messages ?? [])].reverse().find((m) => m.role === "user");
416→  if (!lastUserMessage) {
417→    return { body: originalBody };
418→  }
419→
420→  // 4. Embed last user message
421→  const queryEmbedding = await embedUserMessage(
422→    deps.embeddingModel,
423→    deps.config.embeddingDimension,
424→    lastUserMessage.content,
425→  );
426→
427→  let selectedCandidates;
428→  if (queryEmbedding) {
429→    // 5. Rank candidates by weighted cosine similarity
430→    const ranked = rankCandidates(allCandidates, queryEmbedding);
431→    // 6. Select within token budget
432→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
433→  } else {
434→    // No embedding available -- fall back to all candidates within budget
435→    const ranked = allCandidates.map((c) => ({
436→      id: c.id,
437→      type: c.type,
438→      text: c.text,
439→      score: c.weight,
440→    }));
441→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
442→  }
443→
444→  if (selectedCandidates.length === 0) {
445→    return { body: originalBody };
446→  }
447→
448→  // 7. Build XML block
449→  const brainContextXml = buildBrainContextXml(selectedCandidates);
450→
451→  // 8. Inject into system prompt
452→  const injectionResult = injectBrainContext(parsedBody.system, brainContextXml);
453→
454→  // 9. Build modified request body
455→  const modifiedBody = {
456→    ...parsedBody,
457→    system: injectionResult.system,
458→  };
459→
460→  return {
461→    body: JSON.stringify(modifiedBody),
462→    injectionResult,
463→  };
464→}
465→
466→// ---------------------------------------------------------------------------
467→// Intelligence Metadata Builder (pure)
468→// ---------------------------------------------------------------------------
469→
470→function buildIntelligenceMetadata(injectionResult: InjectionResult) {
471→  return {
472→    brain_context_injected: injectionResult.injected,
473→    brain_context_decisions: injectionResult.decisionsCount,
474→    brain_context_learnings: injectionResult.learningsCount,
475→    brain_context_observations: injectionResult.observationsCount,
476→    brain_context_tokens_est: injectionResult.tokensEstimated,
477→  };
478→}
479→
480→// ---------------------------------------------------------------------------
481→// Non-Streaming Response Content Extraction (for trace output)
482→// ---------------------------------------------------------------------------
483→
484→type ResponseContent = {
485→  content_blocks: Array<{ type: string; text?: string; id?: string; name?: string; input?: unknown }>;
486→  stop_reason: string;
487→  usage: {
488→    input_tokens: number;
489→    output_tokens: number;
490→    cache_creation_tokens?: number;
491→    cache_read_tokens?: number;
492→  };
493→};
494→
495→function extractResponseContent(responseBody: string): ResponseContent | undefined {
496→  try {
497→    const parsed = JSON.parse(responseBody);
498→    if (!parsed.content || !parsed.usage) return undefined;
499→
500→    return {
501→      content_blocks: parsed.content,
502→      stop_reason: parsed.stop_reason ?? "end_turn",
503→      usage: {
504→        input_tokens: parsed.usage.input_tokens ?? 0,
505→        output_tokens: parsed.usage.output_tokens ?? 0,
506→        cache_creation_tokens: parsed.usage.cache_creation_input_tokens,
507→        cache_read_tokens: parsed.usage.cache_read_input_tokens,
508→      },
509→    };
510→  } catch {
511→    return undefined;
512→  }
513→}
514→
515→// ---------------------------------------------------------------------------
516→// Policy Denial Response Builder
517→// ---------------------------------------------------------------------------
518→
519→function buildPolicyDenialResponse(
520→  result: Exclude<ProxyPolicyResult, { decision: "allow" }>,
521→): Response {
522→  if (result.decision === "deny_rate_limit") {
